import sys
from math import gcd
from functools import reduce

MOD = 10**9 + 7

def lcm(a, b):
    return a * b // gcd(a, b)

def hyperrectangle_gcd_sum(K, dimensions):
    def compute_gcd_sum(n):
        total = 0
        for i in range(1, n+1):
            count = 0
            for j in range(1, n//i + 1):
                count += n // (i * j)
            total += i * count
        return total

    if K == 1:
        return compute_gcd_sum(dimensions[0])

    l = 1
    for d in dimensions:
        l = lcm(l, d)

    return (l * compute_gcd_sum(l)) % MOD

