class Solution:
    def __init__(self):
        self.t = int(data[0])
        self.index = 1
        self.results = []

    def read_case(self):
        n = int(data[self.index])
        self.index += 1
        dishes = []
        for _ in range(n):
            a = int(data[self.index])
            b = int(data[self.index + 1])
            m = int(data[self.index + 2])
            self.index += 3
            dishes.append((a, b, m))
        return dishes

    def process_case(self):
        dishes = self.read_case()
        variety = len(set(dishes))
        for i in range(len(dishes)):
            a, b, m = dishes[i]
            if m == 0:
                dishes[i] = (0, 0, 0)
            elif m == a:
                dishes[i] = (a, 0, 0)
            elif m == b:
                dishes[i] = (0, b, 0)
            else:
                dishes[i] = (m - b, b, m)
        self.results.append(variety)
        for d in dishes:
            print(f"{d[0]} {d[1]}")

    def run(self):
        for _ in range(self.t):
            self.process_case()
        for result in self.results:
            print(result)

