import sys
input = sys.stdin.read
data = input().split()

class Solution:
    def __init__(self):
        self.t = int(data[0])
        self.index = 1
        self.results = []

    def read_case(self):
        n = int(data[self.index])
        self.index += 1
        dishes = []
        for _ in range(n):
            a = int(data[self.index])
            b = int(data[self.index + 1])
            m = int(data[self.index + 2])
            self.index += 3
            dishes.append((a, b, m))
        return dishes

    def solve_case(self, dishes):
        from collections import defaultdict
        from heapq import heapify, heappop, heappush

        variety = defaultdict(int)
        heap = []

        for a, b, m in dishes:
            if m == 0:
                variety[(a, b)] += 1
            else:
                heappush(heap, (-a, -b, m))

        while heap:
            a, b, m = heappop(heap)
            a, b = -a, -b

            if m <= a:
                variety[(a-m, b)] += 1
                heappush(heap, (-a+m, -b, 0))
            elif m <= b:
                variety[(a, b-m)] += 1
                heappush(heap, (-a, -b+m, 0))
            else:
                variety[(a-b, 0)] += 1
                variety[(0, b-a)] += 1
                heappush(heap, (-a+b, -b+a, 0))

        min_variety = len(variety)
        result = []

        for a, b, m in dishes:
            if m == 0:
                result.append((a, b))
            else:
                for va, vb in variety.keys():
                    if va >= a and vb >= b and va - a + vb - b == m:
                        result.append((va - a, vb - b))
                        break

        self.results.append(min_variety)
        for r in result:
            print(r[0], r[1])

def main():
    sol = Solution()
    for _ in range(sol.t):
        dishes = sol.read_case()
        sol.solve_case(dishes)

if __name__ == "__main__":
    main()

