        return dishes

    def solve_case(self, dishes):
        from collections import defaultdict
        variety_count = defaultdict(int)
        for a, b, m in dishes:
            if m == 0:
                variety_count[(a, b)] += 1
            else:
                x = min(a, m)
                y = m - x
                variety_count[(x, y)] += 1
        min_variety = min(variety_count.values())
        result = []
        for a, b, m in dishes:
            if m == 0:
                result.append((0, 0))
