class Solution:
    def __init__(self):
        self.t = int(data[0])
        self.index = 1
        self.results = []

    def read_case(self):
        n = int(data[self.index])
        self.index += 1
        dishes = []
        for _ in range(n):
            a = int(data[self.index])
            b = int(data[self.index + 1])
            m = int(data[self.index + 2])
            self.index += 3
            dishes.append((a, b, m))
        return dishes

    def solve_case(self, dishes):
        from collections import defaultdict
        variety_count = defaultdict(int)
        for a, b, m in dishes:
            if m == 0:
                variety_count[(a, b)] += 1
            else:
                variety_count[(a - min(a, m), b - min(b, m))] += 1
        min_variety = min(variety_count.values())
        result = []
        for a, b, m in dishes:
            if m == 0:
                result.append((0, 0))
            else:
                x = min(a, m)
                y = m - x
                result.append((x, y))
        return min_variety, result

