        for _ in range(self.t):
            dishes = self.read_case()
            min_variety, result = self.solve_case(dishes)
            self.results.append(min_variety)
            for r in result:
                self.results.append(r)

    def print_results(self):
        for result in self.results:
            if isinstance(result, int):
                print(result)
            else:
                print(*result)

