        self.idx += 1
        dishes = []
        for _ in range(n):
            a = int(data[self.idx])
            b = int(data[self.idx + 1])
            m = int(data[self.idx + 2])
            self.idx += 3
            dishes.append((a, b, m))
        return dishes

    def solve_case(self, dishes):
        from collections import defaultdict
        count = defaultdict(int)
        for a, b, m in dishes:
            count[(a, b)] += 1

        min_variety = len(count)

        for a, b, m in dishes:
            if count[(a, b)] > 1:
                count[(a, b)] -= 1
                if count[(a, b)] == 1:
                    min_variety -= 1
                x = min(m, a)
                y = m - x
                count[(x, y)] += 1
                if count[(x, y)] == 1:
                    min_variety += 1

        self.results.append(min_variety)
        for a, b, m in dishes:
            x = min(m, a)
            y = m - x
            self.results.append(f"{x} {y}")

    def run(self):
        for _ in range(self.t):
            dishes = self.read_case()
            self.solve_case(dishes)

