    for v in range(u + 1, m):
        for i in range(n):
            if u + 1 in ice_creams[i] and v + 1 in ice_creams[i]:
                G[u].append(v)
                G[v].append(u)

# Function to find articulation points and bridges
def dfs(node, parent, visited, disc, low, ap, bridges):
    children = 0
    visited[node] = True
    disc[node] = low[node] = time
    time += 1

    for neighbor in G[node]:
        if not visited[neighbor]:
            children += 1
            dfs(neighbor, node, visited, disc, low, ap, bridges)
            low[node] = min(low[node], low[neighbor])

            if parent != -1 and low[neighbor] >= disc[node]:
                ap[node] = True

            if low[neighbor] > disc[node]:
                bridges.add((node, neighbor))

        elif neighbor != parent:
            low[node] = min(low[node], disc[neighbor])

def find_articulations_and_bridges():
    visited = [False] * m
    disc = [-1] * m
    low = [-1] * m
    ap = [False] * m
    bridges = set()
    global time
    time = 0

    for i in range(m):
        if not visited[i]:
            dfs(i, -1, visited, disc, low, ap, bridges)

    return ap, bridges

