def bfs_chromatic_number(graph):
    colors = [-1] * len(graph)
    for start in range(len(graph)):
        if colors[start] == -1:
            queue = deque([start])
            colors[start] = 0
            while queue:
                current = queue.popleft()
                for neighbor in graph[current]:
                    if colors[neighbor] == -1:
                        colors[neighbor] = (colors[current] + 1) % 2
                        queue.append(neighbor)
    return max(colors) + 1

