    for j in range(m):
        if i != j:
            for u in components[i]:
                for v in components[j]:
                    if len(u & v) > 0:
                        G[i].append(j)
                        break

# Topological sort to find the chromatic number
in_degree = [0] * m
for i in range(m):
    for j in G[i]:
